import{_ as i,o as t,c as a,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"NativeLink™ Deferred Deep Linking","description":"","frontmatter":{"title":"NativeLink™ Deferred Deep Linking","slug":"nativelink-deferred-deep-linking"},"headers":[],"relativePath":"developer-hub/nativelink-deferred-deep-linking.md","filePath":"developer-hub/nativelink-deferred-deep-linking.md"}'),o={name:"developer-hub/nativelink-deferred-deep-linking.md"};function r(l,e,s,h,d,c){return t(),a("div",null,[...e[0]||(e[0]=[n('<div class="info custom-block"><p class="custom-block-title">Note</p><p>If you are currently using the <strong>Branch NativeLink feature on iOS 16</strong>, when the Branch SDK checks the pasteboard on first opens, the native iOS prompt will automatically display itself requesting permission from the user. Alternative integrations are supported. Please refer to our <a href="https://help.branch.io/developers-hub/docs/ios-advanced-features#nativelink%E2%84%A2-deferred-deep-linking" target="_blank" rel="noreferrer">iOS Developer Docs</a>.</p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>NativeLink™ is an innovation from Branch that bridges the gap created by Private Relay with an on-device solution that does not require the use of an IP address for deferred deep linking.</p><p>NativeLink™ gives end-users the choice to copy deep link content to their clipboard or not, so they have full control of their user experience.</p><p>With no unique personally identifiable information (PII) required, there is no privacy-comprising tracking with NativeLink™. It works by utilizing the native copy and paste functionality already built into their iPhone.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><ol><li>User clicks a Branch Link.</li><li>User&#39;s web browser opens and the user will see the NativeLink™ experience — a blue call-to-action button.</li><li>Once they click on the CTA, the URL location is copied to the clipboard.</li><li>The user is then brought to the App Store to download the app.</li><li>After installation, NativeLink™ will check the clipboard for the URL and process it for deep linking. The user is then routed to their final destination in the app.</li></ol><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h2><p>Access to Deferred Deep Linking requires a premium plan. Please visit our <a href="https://www.branch.io/pricing/" target="_blank" rel="noreferrer">Pricing</a> page or <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">contact our Sales team</a> to learn more about pricing and availability.</p><h2 id="integration-guide" tabindex="-1">Integration guide <a class="header-anchor" href="#integration-guide" aria-label="Permalink to &quot;Integration guide&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>Developers knowledgeable with mobile development are required.</p></div><h4 id="_1-make-sure-your-branch-ios-sdk-is-v1-39-4" tabindex="-1">1. Make sure your <a href="./ios-sdk-overview.html">Branch iOS SDK</a> is v1.39.4+ <a class="header-anchor" href="#_1-make-sure-your-branch-ios-sdk-is-v1-39-4" aria-label="Permalink to &quot;1. Make sure your [Branch iOS SDK](ios-sdk-overview.md) is v1.39.4+&quot;">​</a></h4><p>Ensure that your mobile app is set up for deep-linked routing from Branch Links.</p><h4 id="_2-implement-a-single-line-of-code-for-the-app-to-process-a-nativelinktm-enabled-branch-link" tabindex="-1">2. Implement a single line of code for the app to process a NativeLink™ enabled Branch Link <a class="header-anchor" href="#_2-implement-a-single-line-of-code-for-the-app-to-process-a-nativelinktm-enabled-branch-link" aria-label="Permalink to &quot;2. Implement a single line of code for the app to process a NativeLink™ enabled Branch Link&quot;">​</a></h4><p>Please follow the instructions in our <a href="./ios-advanced-features.html#nativelink™-deferred-deep-linking">developer documentation</a> for implementing the single line of code.</p><h4 id="_3-toggle-nativelinktm-on-in-the-branch-dashboard" tabindex="-1">3. Toggle NativeLink™ on in the <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">Branch Dashboard</a> <a class="header-anchor" href="#_3-toggle-nativelinktm-on-in-the-branch-dashboard" aria-label="Permalink to &quot;3. Toggle NativeLink™ on in the [Branch Dashboard](https://dashboard.branch.io/configuration/general)&quot;">​</a></h4><p>Select your audience rule.</p><h4 id="_4-create-and-configure-your-branch-link" tabindex="-1">4. Create and configure your Branch Link <a class="header-anchor" href="#_4-create-and-configure-your-branch-link" aria-label="Permalink to &quot;4. Create and configure your Branch Link&quot;">​</a></h4><p>Branch Link creation options:</p><ul><li><a href="./create-quick-links.html">Short Links</a></li><li><a href="./deep-linking-api.html">Deep Linking API</a></li><li><a href="./native-sdks-overview.html">Mobile SDKs</a></li><li><a href="./web-sdk-overview.html">Web SDK</a></li><li><a href="https://chrome.google.com/webstore/detail/branch-link-creator/pekdpppibljpmpbcjelehhnldnfbglgf" target="_blank" rel="noreferrer">Chrome Extension</a></li></ul><p>Additional information on configuring your Branch Links can be found <a href="./creating-a-deep-link.html">here</a>.</p><h2 id="nativelinktm-customization" tabindex="-1">NativeLink™ customization <a class="header-anchor" href="#nativelinktm-customization" aria-label="Permalink to &quot;NativeLink™ customization&quot;">​</a></h2><h4 id="_1-find-the-nativelinktm-deepview" tabindex="-1">1. Find the NativeLink™ Deepview <a class="header-anchor" href="#_1-find-the-nativelinktm-deepview" aria-label="Permalink to &quot;1. Find the NativeLink™ Deepview&quot;">​</a></h4><p>Go to the <a href="https://dashboard.branch.io/deepview/deepview-manager" target="_blank" rel="noreferrer">Deepview Manager</a> tab under <strong>Campaigns</strong> in the left-side navigation. Once there, locate the NativeLink™ default Deepview indicated by the following tooltip:</p><p><em>[Image: 896]</em>.png &quot;NativeLink Deepview.png&quot;)<br> You have the following options:</p><ul><li><strong>Edit</strong>: Opens the edit screen for the Deepview. This option is <strong>only available</strong> on cloned Deepviews.</li><li><strong>Set as NativeLink™ Default</strong>: Makes the Deepview the default only for NativeLink™ experiences.</li><li><strong>Duplicate</strong>: Clones the Deepview. This option is <strong>only available</strong> on the default Deepview.</li><li><strong>Delete</strong>: Deletes the Deepview. This option is <strong>only available</strong> on cloned deepviews.</li></ul><h2 id="testing-and-troubleshooting" tabindex="-1">Testing and troubleshooting <a class="header-anchor" href="#testing-and-troubleshooting" aria-label="Permalink to &quot;Testing and troubleshooting&quot;">​</a></h2><p>Because enabling and using NativeLink™ requires iOS development resources, you can find our NativeLink™ testing &amp; troubleshooting steps in our <a href="./ios-troubleshooting.html">developer documentation</a>.</p><h2 id="a-b-testing-nativelinktm" tabindex="-1">A/B testing NativeLink™ <a class="header-anchor" href="#a-b-testing-nativelinktm" aria-label="Permalink to &quot;A/B testing NativeLink™&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Note</p><p>Setting up an A/B test with one or more NativeLink™ Deepviews requires advanced link setup steps.</p></div><p>With NativeLink™, you have the ability to test out different designs at the same time and control the release the control of those accessing the NativeLink™ Deepview on the link level.</p><h4 id="_1-getting-nativelinktm-keys" tabindex="-1">1. Getting NativeLink™ keys <a class="header-anchor" href="#_1-getting-nativelinktm-keys" aria-label="Permalink to &quot;1. Getting NativeLink™ keys&quot;">​</a></h4><p>When you are <a href="./nativelink-deferred-deep-linking.html#nativelink™-customization">customizing your NativeLink™ Deepview</a>, each new Deepview you create will have its own unique <strong>key</strong>.</p><p>You can obtain the key from the <a href="https://dashboard.branch.io/configuration/deepview-manager" target="_blank" rel="noreferrer">Deepview Manager</a>. Each key is located underneath the title of the Deepview.</p><p>Note the keys of the different NativeLink™ Deepviews that you are going to use for the A/B test.</p><h4 id="_2-set-nativelinktm-keys" tabindex="-1">2. Set NativeLink™ keys <a class="header-anchor" href="#_2-set-nativelinktm-keys" aria-label="Permalink to &quot;2. Set NativeLink™ keys&quot;">​</a></h4><p>Once you have the keys of the Deepviews you are going to use for the A/B test, you need to set those keys on a per-link basis using the <code>$ios_nativelink</code> <a href="./creating-a-deep-link.html#deep-linking">parameter</a>. Each Deepview will need to have its own corresponding <a href="./create-quick-links.html">Branch Short Link</a>.</p><p>Set your NativeLink keys as the value for <code>$ios_nativelink</code> when <a href="./create-quick-links.html#4-add-link-data-optional">adding link data options</a>.</p><p>Note that NativeLink configurations are a form of &quot;Active Deepviews&quot;, so <a href="./creating-a-deep-link.html#forced-redirections">forced redirections</a> will not work with it.</p><h4 id="_3-launch-a-b-test" tabindex="-1">3. Launch A/B test <a class="header-anchor" href="#_3-launch-a-b-test" aria-label="Permalink to &quot;3. Launch A/B test&quot;">​</a></h4><p>You can then use your preferred A/B testing platform to send out your Branch from the previous step to start getting data and usage on the NativeLink™ experiences.</p><h4 id="_4-measure-a-b-performance" tabindex="-1">4. Measure A/B performance <a class="header-anchor" href="#_4-measure-a-b-performance" aria-label="Permalink to &quot;4. Measure A/B performance&quot;">​</a></h4><p>The performance of the Branch Short Link can be <a href="https://help.branch.io/v1/docs/create-quick-links#viewing-quick-links-in-the-dashboard" target="_blank" rel="noreferrer">viewed on the Branch Dashboard</a>.</p><p>You can then use these metrics to determine the winner of your A/B test, and set one of them to be the NativeLink™ Default.</p>',44)])])}const k=i(o,[["render",r]]);export{u as __pageData,k as default};
